#!/usr/bin/env node
/**
 * RELEASE-AUTOMATION-GUARD-NONPUBLISH-COMMITS-001 — Layer 1 verification.
 *
 * Invokes the REAL @semantic-release/commit-analyzer against the releaseRules
 * generated by createPackageConfig() in scripts/multi-package-release.mjs.
 * This is the load-bearing test for Layer 1: it asserts that semantic-release
 * actually interprets the deny rules the way the dry-run simulation predicts.
 *
 * Without this check, Layer 1 is only validated by a local reimplementation
 * of rule matching, which could disagree with semantic-release's actual rule
 * precedence (esp. order-sensitive evaluation, scope:undefined behavior, and
 * the preset's catch-all rules).
 *
 * Cases (synthetic commits, no git mutation):
 *   - fix(caws-kernel):         → expect null
 *   - fix(specs):               → expect null
 *   - fix(caws-cli):            → expect 'patch'
 *   - feat(caws-cli):           → expect 'minor'
 *   - fix(packages/caws-cli):   → expect 'patch'
 *   - BREAKING + scope:caws-kernel → expect null (deny rule with breaking:true)
 *
 * Run:  node scripts/release-guard-commit-analyzer-check.mjs
 * Exit: 0 if all cases match expected; 1 otherwise.
 */

import { analyzeCommits } from '@semantic-release/commit-analyzer';

import { PACKAGES, createPackageConfig } from './multi-package-release.mjs';

const cliPkg = PACKAGES.find((p) => p.scope === 'cli');
if (!cliPkg) {
  console.error('FATAL: no PACKAGES entry with scope:cli');
  process.exit(2);
}

// createPackageConfig returns a `module.exports = {...}` string. Parse the
// JSON portion (it's pretty-printed JSON inside the wrapper).
const configString = createPackageConfig(cliPkg);
const jsonStart = configString.indexOf('{');
const jsonEnd = configString.lastIndexOf('}');
const generatedConfig = JSON.parse(configString.slice(jsonStart, jsonEnd + 1));

// Extract the commit-analyzer plugin config (it's the first plugin entry).
const caEntry = generatedConfig.plugins.find(
  (p) => Array.isArray(p) && p[0] === '@semantic-release/commit-analyzer'
);
if (!caEntry) {
  console.error('FATAL: generated config has no @semantic-release/commit-analyzer plugin entry');
  process.exit(2);
}
const caPluginConfig = caEntry[1];

console.log('═══════════════════════════════════════════════════════════════════════════');
console.log('RELEASE-AUTOMATION-GUARD-NONPUBLISH-COMMITS-001 — commit-analyzer check');
console.log('═══════════════════════════════════════════════════════════════════════════');
console.log('');
console.log(`Generated:        ${new Date().toISOString()}`);
console.log(`Package:          ${cliPkg.name} (scope: ${cliPkg.scope})`);
console.log(`releaseRules:     ${caPluginConfig.releaseRules.length} rules`);
console.log(`Plugin preset:    ${caPluginConfig.preset}`);
console.log('');

// Build synthetic commits matching the shape semantic-release expects.
// A commit object: { hash, message, header, body, footer, ...parsed fields }.
// commit-analyzer parses the commit message through conventional-commits-parser,
// so passing just { message } is sufficient — the parser fills in type/scope/subject.
const CASES = [
  { id: 'D1', message: 'fix(caws-kernel): event chain repair', expectedRelease: null, note: 'Layer 1 deny rule (kernel scope)' },
  { id: 'D2', message: 'fix(specs): spec hygiene', expectedRelease: null, note: 'Layer 1 deny rule' },
  { id: 'D3', message: 'fix(docs): doc fix', expectedRelease: null, note: 'Layer 1 deny rule' },
  { id: 'D4', message: 'fix(ci): CI fix', expectedRelease: null, note: 'Layer 1 deny rule' },
  { id: 'D5', message: 'fix(tests): test fix', expectedRelease: null, note: 'Layer 1 deny rule' },
  { id: 'A1', message: 'fix(cli): real cli fix', expectedRelease: 'patch', note: 'owned scope (short)' },
  { id: 'A2', message: 'feat(cli): real cli feature', expectedRelease: 'minor', note: 'owned scope (short)' },
  { id: 'A3', message: 'fix(packages/caws-cli): real cli fix', expectedRelease: 'patch', note: 'owned scope (path form)' },
  { id: 'A4', message: 'feat(packages/caws-cli): real cli feature', expectedRelease: 'minor', note: 'owned scope (path form)' },
  // Breaking-change cases. BREAKING CHANGE in footer or "!" before colon.
  {
    id: 'B1',
    message: 'fix(caws-kernel): change\n\nBREAKING CHANGE: scope is non-owned',
    expectedRelease: null,
    note: 'Layer 1 breaking:true + scope:caws-kernel deny',
  },
  {
    id: 'B2',
    message: 'feat(cli): breaking change\n\nBREAKING CHANGE: surface API broken',
    expectedRelease: 'major',
    note: 'breaking:true + owned scope → major',
  },
  // No-scope cases — semantic-release default behavior (preset's fix → patch).
  // With our deny list, unscoped commits are NOT denied (scope is undefined,
  // not in NON_OWNED_SCOPES). Document the actual behavior.
  {
    id: 'U1',
    message: 'fix: unscoped fix',
    expectedRelease: 'patch',
    note: 'unscoped commit — preset default applies; deny list does NOT match undefined scope',
  },
];

const ctx = {
  commits: [], // populated per case below
  cwd: process.cwd(),
  env: {},
  logger: {
    log: () => {},
    error: () => {},
    warn: () => {},
    info: () => {},
    success: () => {},
    debug: () => {},
  },
  options: {},
  stdout: process.stdout,
  stderr: process.stderr,
};

let passed = 0;
let failed = 0;
const failures = [];

for (const c of CASES) {
  ctx.commits = [{ hash: 'fake-' + c.id, message: c.message }];
  let result;
  let errorOut = null;
  try {
    // analyzeCommits is async; await its return.
    result = await analyzeCommits(caPluginConfig, ctx);
  } catch (e) {
    errorOut = e.message || String(e);
  }
  const got = result === undefined ? null : result;
  const ok = got === c.expectedRelease;
  console.log(
    `[${c.id}] ${ok ? 'PASS' : 'FAIL'}  expected=${JSON.stringify(c.expectedRelease)}  got=${JSON.stringify(got)}  msg="${c.message.split('\n')[0]}"`
  );
  if (errorOut) console.log(`        ERROR: ${errorOut}`);
  console.log(`        note: ${c.note}`);
  if (ok) passed++;
  else {
    failed++;
    failures.push({ id: c.id, message: c.message, expected: c.expectedRelease, got, note: c.note });
  }
}

console.log('');
console.log('═══════════════════════════════════════════════════════════════════════════');
console.log(`SUMMARY: ${passed} passed, ${failed} failed (${CASES.length} total)`);
if (failures.length > 0) {
  console.log('');
  console.log('Failures:');
  for (const f of failures) {
    console.log(`  [${f.id}] expected=${JSON.stringify(f.expected)} got=${JSON.stringify(f.got)}`);
    console.log(`        message: ${f.message.split('\n')[0]}`);
    console.log(`        note:    ${f.note}`);
  }
}
console.log('═══════════════════════════════════════════════════════════════════════════');
process.exit(failed === 0 ? 0 : 1);
